const RAF_FALLBACK_MS=16;const FONT_LOAD_TIMEOUT_MS=1500;if(!window.requestAnimationFrame){window.requestAnimationFrame=function(callback){return setTimeout(callback,RAF_FALLBACK_MS)}}function updateHeaderHeight(){const header=document.querySelector("header");if(header){const height=header.offsetHeight;document.documentElement.style.setProperty("--header-height",`${height}px`)}}updateHeaderHeight();window.addEventListener("resize",updateHeaderHeight);if(document.fonts&&document.fonts.ready){document.fonts.ready.then(()=>{updateHeaderHeight()})}else{setTimeout(updateHeaderHeight,FONT_LOAD_TIMEOUT_MS)}function initHeaderTitleVisibility(retryCount=0){const heroTitle=document.querySelector(".hero h1");const headerTitleWrapper=document.querySelector(".header-title-wrapper");const headerTitleLink=document.querySelector(".header-title-link");const headerContainer=document.querySelector(".header-container");if(!heroTitle||!headerTitleWrapper||!headerContainer){if(retryCount<3){setTimeout(()=>initHeaderTitleVisibility(retryCount+1),500)}return}headerTitleWrapper.classList.remove("visible");headerContainer.classList.remove("title-visible");if(headerTitleLink){headerTitleLink.setAttribute("aria-hidden","true");headerTitleLink.setAttribute("tabindex","-1")}let lastLogoState=false;const observer=new IntersectionObserver(entries=>{entries.forEach(entry=>{const shouldShowLogo=entry.intersectionRatio<.2;if(shouldShowLogo===lastLogoState)return;lastLogoState=shouldShowLogo;if(shouldShowLogo){if(!headerTitleWrapper.classList.contains("visible")){headerTitleWrapper.classList.add("visible");headerContainer.classList.add("title-visible");if(headerTitleLink){headerTitleLink.setAttribute("aria-hidden","false");headerTitleLink.setAttribute("tabindex","0")}}}else{if(headerTitleWrapper.classList.contains("visible")){headerTitleWrapper.classList.remove("visible");headerContainer.classList.remove("title-visible");if(headerTitleLink){headerTitleLink.setAttribute("aria-hidden","true");headerTitleLink.setAttribute("tabindex","-1")}}}})},{rootMargin:"0px 0px 0px 0px",threshold:[0,.2]});observer.observe(heroTitle)}function initActiveNavLink(){const sections=document.querySelectorAll("section[id]");const navLinks=document.querySelectorAll('nav a[href^="#"]');if(sections.length===0||navLinks.length===0){return}const sectionMap={};navLinks.forEach(link=>{const href=link.getAttribute("href");if(href&&href.startsWith("#")){const sectionId=href.slice(1);sectionMap[sectionId]=link}});const sectionObserver=new IntersectionObserver(entries=>{entries.forEach(entry=>{const sectionId=entry.target.id;const link=sectionMap[sectionId];if(!link)return;if(entry.isIntersecting){navLinks.forEach(l=>{l.removeAttribute("aria-current")});link.setAttribute("aria-current","page")}})},{rootMargin:"-85px 0px -66% 0px",threshold:[0,.5]});sections.forEach(section=>{sectionObserver.observe(section)})}function initDynamicConcentricCircles(){const ghirondaImg=document.querySelector(".ghironda-icon");const ghirondaWrapper=document.querySelector(".ghironda-wrapper");if(!ghirondaImg||!ghirondaWrapper)return;let lastSvgUrl=null;function generateCircles(){const rect=ghirondaImg.getBoundingClientRect();const width=rect.width;const height=rect.height;if(width===0||height===0){requestAnimationFrame(generateCircles);return}const diagonal=Math.sqrt(width*width+height*height);const r1=diagonal/2;const heroRect=ghirondaImg.closest(".hero").getBoundingClientRect();const imgCenterX=rect.left+width/2;const imgCenterY=rect.top+height/2;const distTopLeft=Math.sqrt((imgCenterX-heroRect.left)**2+(imgCenterY-heroRect.top)**2);const distTopRight=Math.sqrt((heroRect.right-imgCenterX)**2+(imgCenterY-heroRect.top)**2);const distBottomLeft=Math.sqrt((imgCenterX-heroRect.left)**2+(heroRect.bottom-imgCenterY)**2);const distBottomRight=Math.sqrt((heroRect.right-imgCenterX)**2+(heroRect.bottom-imgCenterY)**2);const r9=Math.max(distTopLeft,distTopRight,distBottomLeft,distBottomRight)*.95;const ratio=Math.pow(r9/r1,1/8);const fillColors=["#8B3A3A","#7A2F2F","#6B2424","#5A1A1A","#4A1515","#3A0F0F","#2A0A0A","#1a0505","#0a0000"];let circlesHtml="";for(let i=8;i>=0;i--){const baseRadius=r1*Math.pow(ratio,i);const numPoints=200;const maxAmplitude=baseRadius*(.04+i*.01);const baseFrequency=2;const numOctaves=3;let pathD="";for(let j=0;j<=numPoints;j++){const angle=j/numPoints*Math.PI*2;let perturbation=0;let amplitude=maxAmplitude;let frequency=baseFrequency;for(let octave=0;octave<numOctaves;octave++){perturbation+=Math.sin(angle*frequency)*amplitude;frequency*=2;amplitude*=.5}const radius=baseRadius+perturbation;const x=radius*Math.cos(angle);const y=radius*Math.sin(angle);pathD+=(j===0?"M":"L")+x.toFixed(1)+","+y.toFixed(1)}pathD+="Z";const fillOpacity=.8-i*.08;circlesHtml+=`<path d="${pathD}" fill="${fillColors[8-i]}" fill-opacity="${fillOpacity.toFixed(3)}" stroke="none"/>`;const sw=2.2+i/8*3.5;const baseStrokeOpacity=.95-i*.07;const strokeOpacity=Math.max(baseStrokeOpacity,.4);const strokeColor=i===0?"#000000":"#330000";circlesHtml+=`<path d="${pathD}" fill="none" stroke="${strokeColor}" stroke-width="${sw.toFixed(1)}" opacity="${strokeOpacity.toFixed(2)}" stroke-linecap="round" stroke-linejoin="round"/>`}const vb=r9*2.1;const vbHalf=Math.floor(vb/2);const svgHtml=`<svg xmlns="http://www.w3.org/2000/svg" viewBox="${-vbHalf} ${-vbHalf} ${Math.ceil(vb)} ${Math.ceil(vb)}" width="${Math.ceil(vb)}" height="${Math.ceil(vb)}"><g>${circlesHtml}</g></svg>`;const svgUrl=`url('data:image/svg+xml;utf8,${encodeURIComponent(svgHtml)}')`;if(svgUrl!==lastSvgUrl){lastSvgUrl=svgUrl;document.documentElement.style.setProperty("--ghironda-circles",svgUrl);ghirondaWrapper.style.setProperty("--circle-size",Math.ceil(vb)+"px")}}if(ghirondaImg.complete&&ghirondaImg.naturalWidth>0){generateCircles()}else{ghirondaImg.addEventListener("load",generateCircles)}let resizeTimer;window.addEventListener("resize",()=>{clearTimeout(resizeTimer);resizeTimer=setTimeout(generateCircles,500)})}if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",()=>{initHeaderTitleVisibility();initActiveNavLink();if("requestIdleCallback"in window){requestIdleCallback(()=>{initDynamicConcentricCircles()})}else{setTimeout(initDynamicConcentricCircles,1e3)}})}else{initHeaderTitleVisibility();initActiveNavLink();if("requestIdleCallback"in window){requestIdleCallback(()=>{initDynamicConcentricCircles()})}else{setTimeout(initDynamicConcentricCircles,1e3)}}